       return I;
     Known.fneg();
+    Known.knownNot(~DemandedMask);
     break;
   }
   case Instruction::FAdd:
@@ -2319,17 +2307,14 @@ Value *InstCombinerImpl::SimplifyDemandedUseFPClass(Instruction *I,
